/// Represents a list of errors that can be throw by the service directly.
///  
/// This does not include errors thrown by internal frameworks such as SwiftData.
public enum LearnKitError: Error {
    case rootNodeMissing
    /// Represents an error generated by the LearnInstance.
    ///
    /// - Parameter error: Error generated by the Learn REST API.
    case restError(_ error: RestError)
    /// Represents unknown errors encountered by the service.
    ///
    /// - Parameter statusCode: Status code for the error, if one is available.
    case unknown(statusCode: Int?)
}
